#include <iostream>
#include <vector>
#include <utility>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

class Solution {
public:
    ListNode *deleteDuplicates(ListNode *head) {
		if (!head) return NULL;

		ListNode dummy(0);
		dummy.next = head;
		ListNode *current = &dummy;

		set<int> seen;

		while (current->next) {
			if (seen.find(current->next->val) != seen.end())
				current->next = current->next->next;
			else
			{
				seen.insert(current->next->val);
				current = current->next;
			}
		}
		return dummy.next;
	}
};
